const l = (ru, en) => ({ ru, en })
const w = (ru, en, noteRu, noteEn) => ({ meaning: l(ru, en), note: l(noteRu, noteEn) })
const lx = (es, ru, en, noteRu, noteEn) => [es, w(ru, en, noteRu, noteEn)]
const line = (start, text, ru, en, noteRu, noteEn) => ({ start, text, translation: l(ru, en), explanation: l(noteRu, noteEn) })

