const lyrics = [
  line(8.56, 'Tonto el que no entienda', 'Глуп тот, кто не поймёт.', 'A fool is the one who does not understand.', 'El que обобщает «тот, кто»; entienda стоит в subjuntivo.', 'El que generalizes “the one who”; entienda is subjunctive.'),
  line(12.61, 'Cuenta una leyenda', 'Одна легенда рассказывает…', 'A legend tells…', 'Инверсия делает начало похожим на традиционную балладу.', 'The inversion makes the opening sound like a traditional ballad.'),
  line(16.3, 'Que una hembra gitana', 'Что одна ромская женщина…', 'That a Romani woman…', 'Hembra здесь архаично-поэтическое; в обычной речи лучше mujer.', 'Hembra is archaic/poetic here; mujer is preferable in everyday speech.'),
  line(20.95, 'Conjuró a la luna hasta el amanecer', 'Заклинала луну до самого рассвета.', 'Invoked the moon until dawn.', 'Conjuró — завершённое действие; a отмечает адресата.', 'Conjuró is a completed action; a marks its target.'),
  line(24.65, 'Llorando pedía', 'Плача, она просила…', 'Crying, she begged…', 'Герундий и imperfecto рисуют продолжающуюся сцену.', 'The gerund and imperfect paint an ongoing scene.'),
  line(27.45, 'Al llegar el día', 'Когда наступил день…', 'When day came…', 'Al + infinitivo = «когда / при наступлении».', 'Al + infinitive means “when / upon”.'),
  line(30.0, 'Desposar un calé', 'Выйти замуж за ромского мужчину.', 'To marry a Romani man.', 'Desposar — книжное; calé — культурно специфическое слово.', 'Desposar is literary; calé is culturally specific.'),
  line(39.66, '"Tendrás a tu hombre, piel morena"', '«Ты получишь своего мужчину, смуглокожая».', '“You will have your man, brown-skinned woman.”', 'Прямая речь луны; piel morena используется как обращение.', 'The moon speaks directly; piel morena is used as an address.'),
  line(44.0, 'Desde el cielo habló la luna llena', 'С неба заговорила полная луна.', 'From the sky the full moon spoke.', 'Порядок слов выдвигает место действия вперёд.', 'The word order foregrounds the setting.'),
  line(47.3, '"Pero a cambio quiero', '«Но взамен я хочу…', '“But in return I want…', 'A cambio вводит цену сделки.', 'A cambio introduces the price of the bargain.'),
  line(50.2, 'El hijo primero que le engendres a él', 'Первого сына, которого ты зачнёшь от него.', 'The first son that you bear him.', 'Quiero que вызывает subjuntivo engendres; le и a él дублируют объект для акцента.', 'Quiero que triggers engendres; le and a él double the object for emphasis.'),
  line(55.0, 'Que quien su hijo inmola', 'Ведь тот, кто приносит в жертву своего ребёнка…', 'For whoever sacrifices their child…', 'Inmolar — сильное книжное слово.', 'Inmolar is a strong formal word.'),
  line(59.2, 'Para no estar sola', 'Чтобы не быть одной…', 'So as not to be alone…', 'Para + infinitivo выражает цель.', 'Para + infinitive expresses purpose.'),
  line(63.0, 'Poco le iba a querer"', 'Вряд ли сильно его любил бы».', 'Could hardly have loved him much.”', 'Ir a + infinitivo в imperfecto здесь передаёт оценку: любви было бы мало.', 'Ir a + infinitive in the imperfect gives an evaluation: there would be little love.'),
  line(69.33, 'Luna quieres ser madre', 'Луна, ты хочешь стать матерью.', 'Moon, you want to be a mother.', 'Обращение Luna стоит без отдельной частицы.', 'Luna is a direct address.'),
  line(73.93, 'Y no encuentras querer que te haga mujer', 'Но не находишь любви, которая сделала бы тебя женщиной.', 'And you cannot find a love that would make you a woman.', 'Querer здесь поэтически значит «любовь»; haga — subjuntivo после неопределённого источника любви.', 'Querer poetically means “love”; haga is subjunctive after an unspecified source of love.'),
  line(77.38, 'Dime, luna de plata', 'Скажи мне, серебряная луна.', 'Tell me, silver moon.', 'Dime = di + me, команда decir.', 'Dime is di + me, the command of decir.'),
  line(79.86, '¿Qué pretendes hacer con un niño de piel?', 'Что ты намерена делать с ребёнком из плоти?', 'What do you intend to do with a flesh-and-blood child?', 'Niño de piel — нарочно странный поэтический образ, не обычное современное выражение.', 'Niño de piel is intentionally strange poetic imagery, not a normal modern phrase.'),
  line(84.0, 'Ah-ah-ah-ah, ah-ah-ah-ah', 'Вокализация.', 'Vocalization.', 'Ритмический фрагмент без буквального значения.', 'A rhythmic passage without literal meaning.'),
  line(89.46, 'Hijo de la luna', 'Сын луны.', 'Son of the moon.', 'Название песни и итог рефрена.', 'The title and conclusion of the refrain.'),
  line(99.08, 'De padre canela nació un niño', 'У смуглого отца родился ребёнок.', 'A child was born to a cinnamon-skinned father.', 'Canela метафорически описывает цвет кожи.', 'Canela metaphorically describes complexion.'),
  line(103.1, 'Blanco como el lomo de un armiño', 'Белый, как спина горностая.', 'White as an ermine’s back.', 'Como вводит сравнение.', 'Como introduces a comparison.'),
  line(107.4, 'Con los ojos grises en vez de aceituna', 'С серыми глазами вместо оливковых.', 'With gray eyes instead of olive-colored ones.', 'Aceituna заменяет ожидаемый цвет глаз метонимией.', 'Aceituna stands for the expected eye color by metonymy.'),
  line(111.54, 'Niño albino de luna', 'Лунный ребёнок-альбинос.', 'Albino child of the moon.', 'Краткая именная строка без глагола.', 'A compact verbless nominal line.'),
  line(116.6, '"Maldita su estampa', '«Будь проклят его облик.', '“Curse his appearance.', 'Эмоциональная прямая речь отца.', 'The father’s emotional direct speech.'),
  line(120.0, 'Este hijo es de un payo', 'Этот ребёнок от неромского мужчины.', 'This child belongs to a non-Romani man.', 'Payo — контекстное культурное слово; строка показывает подозрение героя, а не факт.', 'Payo is culturally specific; the line shows the character’s suspicion, not a fact.'),
  line(124.1, 'Y yo no me lo callo"', 'И я об этом молчать не стану».', 'And I will not keep it quiet.”', 'Callarse algo: me + lo + callo.', 'Callarse algo uses me + lo + callo.'),
  line(129.89, 'Luna quieres ser madre', 'Луна, ты хочешь стать матерью.', 'Moon, you want to be a mother.', 'Начало второго припева.', 'The second refrain begins.'),
  line(134.1, 'Y no encuentras querer que te haga mujer', 'Но не находишь любви, которая сделала бы тебя женщиной.', 'And you cannot find a love that would make you a woman.', 'Поэтическое querer используется как имя любви.', 'Poetic querer functions as a name for love.'),
  line(139.0, 'Dime, luna de plata', 'Скажи мне, серебряная луна.', 'Tell me, silver moon.', 'Повтор команды dime.', 'The command dime repeats.'),
  line(143.2, '¿Qué pretendes hacer con un niño de piel?', 'Что ты намерена делать с ребёнком из плоти?', 'What do you intend to do with a flesh-and-blood child?', 'Pretender здесь значит «намереваться».', 'Pretender means “intend” here.'),
  line(148.5, 'Ah-ah-ah-ah, ah-ah-ah-ah', 'Вокализация.', 'Vocalization.', 'Мелодический рефрен.', 'A melodic refrain.'),
  line(154.5, 'Hijo de la luna', 'Сын луны.', 'Son of the moon.', 'Повтор названия.', 'The title repeats.'),
  line(159.64, 'Gitano al creerse deshonrado', 'Ромский мужчина, сочтя себя опозоренным…', 'The Romani man, believing himself dishonored…', 'Al + возвратный инфинитив = «когда/поскольку он счёл себя».', 'Al + reflexive infinitive means “upon/because he believed himself”.'),
  line(163.37, 'Se fue a su mujer, cuchillo en mano', 'Пошёл к своей жене с ножом в руке.', 'Went to his wife, knife in hand.', 'Cuchillo en mano — устойчивая безартиклевая конструкция.', 'Cuchillo en mano is a fixed article-less phrase.'),
  line(169.43, '"¿De quién es el hijo? Me has engañao\' fijo"', '«Чей это ребёнок? Ты точно меня обманула».', '“Whose child is this? You have deceived me for sure.”', 'Engañao\' передаёт разговорное выпадение d; стандартно engañado.', 'Engañao\' represents colloquial loss of d; standard form engañado.'),
  line(173.2, 'Y de muerte la hirió', 'И смертельно ранил её.', 'And mortally wounded her.', 'La — прямой объект; herir de muerte — смертельно ранить.', 'La is the direct object; herir de muerte means mortally wound.'),
  line(177.35, 'Luego se hizo al monte', 'Затем он скрылся в горах.', 'Then he fled into the hills.', 'Hacerse al monte — устойчивое выражение «уйти и скрыться».', 'Hacerse al monte is the fixed expression “flee into the wild”.'),
  line(183.0, 'Con el niño en brazos y allí le abandonó', 'С ребёнком на руках — и там он его оставил.', 'With the child in his arms, and there he abandoned him.', 'En brazos = на руках; le — распространённый испанский leísmo для лица мужского пола.', 'En brazos means in his arms; le is common Spanish leísmo for a male person.'),
  line(191.93, 'Luna quieres ser madre', 'Луна, ты хочешь стать матерью.', 'Moon, you want to be a mother.', 'Третий припев после трагической развязки.', 'The third refrain follows the tragedy.'),
  line(196.0, 'Y no encuentras querer que te haga mujer', 'Но не находишь любви, которая сделала бы тебя женщиной.', 'And you cannot find a love that would make you a woman.', 'Повтор теперь звучит как упрёк.', 'The repetition now sounds accusatory.'),
  line(200.2, 'Dime, luna de plata', 'Скажи мне, серебряная луна.', 'Tell me, silver moon.', 'Обращение к луне.', 'An address to the moon.'),
  line(204.2, '¿Qué pretendes hacer con un niño de piel?', 'Что ты намерена делать с ребёнком из плоти?', 'What do you intend to do with a flesh-and-blood child?', 'Вопрос возвращает внимание к судьбе ребёнка.', 'The question returns attention to the child’s fate.'),
  line(209.2, 'Ah-ah-ah-ah, ah-ah-ah-ah', 'Вокализация.', 'Vocalization.', 'Финальный полный рефрен.', 'The final full refrain.'),
  line(214.5, 'Hijo de la luna', 'Сын луны.', 'Son of the moon.', 'Название становится буквальным внутри легенды.', 'Within the legend, the title becomes literal.'),
  line(219.12, 'Y las noches que haya luna llena', 'И в ночи, когда будет полная луна…', 'And on nights when there is a full moon…', 'Будущие неопределённые ночи требуют haya.', 'Future unspecified nights take haya.'),
  line(223.1, 'Será porque el niño esté de buenas', 'Это будет потому, что ребёнок в хорошем настроении.', 'It will be because the child is in a good mood.', 'Estar de buenas — разговорное «быть в хорошем настроении».', 'Estar de buenas means to be in a good mood.'),
  line(227.5, 'Y si el niño llora', 'А если ребёнок плачет…', 'And if the child cries…', 'Si без ударения вводит условие.', 'Si without an accent introduces a condition.'),
  line(230.2, 'Menguará la luna para hacerle una cuna', 'Луна пойдёт на убыль, чтобы сделать ему колыбель.', 'The moon will wane to make him a cradle.', 'Будущее menguará; hacer + le → hacerle.', 'Future menguará; hacer + le becomes hacerle.'),
  line(234.2, 'Y si el niño llora', 'А если ребёнок плачет…', 'And if the child cries…', 'Строка повторяется для закольцованного финала.', 'The line repeats to create a circular ending.'),
  line(237.2, 'Menguará la luna para hacerle una cuna', 'Луна пойдёт на убыль, чтобы сделать ему колыбель.', 'The moon will wane to make him a cradle.', 'Фаза луны превращается в материнский жест.', 'The moon’s phase becomes a maternal gesture.'),
]

